mapper.select:
SELECT COUNT(*)
FROM STORE_BOARD_TBL
WHERE MARKET_NO = #{marketNo}
  AND MEMBER_ID = #{memberId}
  AND IS_DELETED = 0

mapper.update:
UPDATE BOARD_TBL
SET BOARD_TITLE   = #{marketTitle},
    BOARD_CONTENT = #{marketContent},
    BOARD_THUMB   = #{productThumb}
WHERE BOARD_NO = #{boardNo}

UPDATE CART_TBL
SET QUANTITY = #{quantity}
WHERE CART_NO = #{cartNo}

mapper.delete:
DELETE FROM CART_TBL
WHERE CART_NO = #{cartNo}
  AND MEMBER_ID = #{memberId}

mapper.update:
UPDATE STORE_BOARD_TBL
SET READ_COUNT = READ_COUNT + 1
WHERE MARKET_NO = #{marketNo}

UPDATE BOARD_COMMENT_TBL
SET BOARD_COMMENT_CONTENT = #{reviewContent},
  IS_SECRET = CASE WHEN #{isPrivate} = 1 THEN 'Y' ELSE 'N' END,
  UPDATED_AT = SYSDATE
WHERE BOARD_COMMENT_NO = #{reviewNo}
  AND BOARD_COMMENT_WRITER = #{memberId}

DELETE FROM BOARD_COMMENT_TBL
WHERE BOARD_COMMENT_NO = #{reviewNo}
  AND BOARD_COMMENT_WRITER = #{memberId}

UPDATE STORE_REVIEW_TBL
SET RATING = #{rating},
    REVIEW_CONT = #{reviewContent},
    REVIEW_THUMB = #{reviewThumb},
    REVIEW_CONTENT = #{reviewContent},
    MEMBER_NICKNAME = #{buyerNickname}
WHERE REVIEW_NO = #{reviewNo}
  AND BUYER_ID = #{buyerId}

UPDATE STORE_REVIEW_TBL
SET IS_DELETED = 1
WHERE REVIEW_NO = #{reviewNo}
  AND BUYER_ID = #{buyerId}

UPDATE STORE_BOARD_TRADEINFO_TBL
SET TRADE_STATUS = #{tradeStatus},
    INVOICE_NUMBER = #{invoiceNumber},
    COURIER_CODE = #{courierCode},
    SHIPPING_STATUS = #{shippingStatus}
WHERE TRADE_NO = #{tradeNo}
